p:10px;"><form class="ajax-action" action="{{ route('marketing.content-posting.sync', $row['id'] ?? '') }}" method="POST" style="margin:0;">@csrf @method('PUT')<button type="submit" style="color:#0369a1; border:none; background:none; cursor:pointer; font-weight:900; font-size:12px; font-family:inherit; padding:0;">Sync</button></form><form class="ajax-action" action="{{ route('marketing.content-posting.destroy', $row['id'] ?? '') }}" method="POST" style="margin:0;">@csrf @method('DELETE')<button type="submit" style="color:#b42318; border:none; background:none; cursor:pointer; font-weight:900; font-size:12px; font-family:inherit; padding:0;">Hapus</button></form></div></td></tr>@php $index++; @endphp @endforeach</tbody></table></div><div class="cp-pagination"><div id="detailPaginationInfo">Menampilkan {{ $paginatedRows->firstItem() ?? 0 }} - {{ $paginatedRows->lastItem() ?? 0 }} dari {{ $paginatedRows->total() }}</div><div class="cp-page-buttons" id="detailPaginationButtons"><a href="{{ $paginatedRows->previousPageUrl() }}" class="cp-page-btn" style="text-decoration:none;color:inherit;" {!! $paginatedRows->onFirstPage() ? 'disabled onclick="return false;"' : '' !!}>Prev</a><span style="font-weight:700;margin:0 10px;">Hal {{ $paginatedRows->currentPage() }} / {{ max(1, $paginatedRows->lastPage()) }}</span><a href="{{ $paginatedRows->nextPageUrl() }}" class="cp-page-btn" style="text-decoration:none;color:inherit;" {!! !$paginatedRows->hasMorePages() ? 'disabled onclick="return false;"' : '' !!}>Next</a></div></div>@endif</section>
            <section class="cp-panel" style="margin-top:20px"><div class="cp-panel-head"><h3 class="cp-panel-title">Laporan Checklist Harian</h3><span class="cp-badge {{ $daily->isEmpty() ? 'empty' : 'ok' }}">{{ $daily->count() }} Hari</span></div><div class="cp-panel-body">@if($daily->isEmpty())<div class="cp-empty">Belum ada data checklist.</div>@else<div class="cp-hint" style="margin-bottom:14px">{{ $isFiltered ? 'Filter aktif. Semua hasil filter ditampilkan.' : 'Tanpa filter, laporan harian dibatasi 5 tanggal per halaman agar halaman tetap ringan.' }}</div><div class="cp-daily" id="dailyCards" data-paginate="{{ !$isFiltered ? '1' : '0' }}" data-per-page="5">@foreach($daily as $dayIndex => $day)<article class="cp-day" data-daily-card="1" data-index="{{ $dayIndex }}"><div class="cp-day-head"><div class="cp-day-info"><h3>{{ $day['tanggal'] ? \Carbon\Carbon::parse($day['tanggal'])->format('d/m/Y') : 'Tanggal '.$day['tgl'] }}</h3><dl><dt>Bulan</dt><dd>{{ $day['bulan'] }}</dd><dt>KPI</dt><dd>{{ $day['kpi'] }} Konten</dd><dt>Creator</dt><dd>{{ $day['creator'] ?: '-' }}</dd><dt>IP</dt><dd>{{ $day['ip_marketing'] ?: '-' }}</dd></dl></div><div class="cp-score"><small>Score</small><strong>{{ number_format($day['score'],2,',','.') }}%</strong></div></div><table><thead><tr><th>Creator</th><th>Judul / Link</th><th>Views</th><th>Status</th></tr></thead><tbody>@for($i=0;$i<max($day['kpi'],$day['items']->count());$i++)@php $item=$day['items'][$i] ?? null; @endphp<tr><td data-label="Creator">{{ $item['creator'] ?? '-' }}</td><td data-label="Judul">@if($item)<span class="cp-main">{{ $item['judul'] ?: 'Tanpa judul' }}</span><br>@if(!empty($item['tiktok']))<a class="cp-mini-link" href="{{ $item['tiktok'] }}" target="_blank">TikTok</a>@endif @if(!empty($item['ig']))<a class="cp-mini-link" href="{{ $item['ig'] }}" target="_blank">Instagram</a>@endif @if(!empty($item['threads']))<a class="cp-mini-link" href="{{ $item['threads'] }}" target="_blank">Threads</a>@endif @if(!empty($item['x']))<a class="cp-mini-link" href="{{ $item['x'] }}" target="_blank">X</a>@endif <span class="cp-sub">{{ $item['metrics_source'] ?? 'manual' }}</span>@else - @endif</td><td data-label="Views" class="num">{{ $item ? number_format($item['total'],0,',','.') : '-' }}</td><td data-label="Status">@if(!$item)<span class="cp-badge empty">Belum Input</span>@elseif(($item['total'] ?? 0) <= 0)<span class="cp-badge warn">Belum Views</span>@else<span class="cp-badge ok">Terinput</span>@endif</td></tr>@endfor</tbody></table></article>@endforeach</div>@if(!$isFiltered && $daily->count() > 5)<div class="cp-pagination" id="dailyPagination"><div id="dailyPaginationInfo">Menampilkan laporan harian</div><div class="cp-page-buttons" id="dailyPaginationButtons"></div></div>@endif @endif</div></section>
