<script src="https://code.jquery.com/jquery-3.7.1.min.js"></script>
<script src="https://cdn.jsdelivr.net/npm/select2@4.1.0-rc.0/dist/js/select2.min.js"></script>
<script>
document.addEventListener('DOMContentLoaded', function () {
    if (window.jQuery && jQuery.fn.select2) { jQuery('.js-select2').select2({width:'100%'}); }

    document.addEventListener('submit', function(e) {
        if (e.target.matches('form.ajax-action')) {
            e.preventDefault();
            const form = e.target;
            const action = form.getAttribute('action');
            const method = form.querySelector('input[name="_method"]')?.value || form.method;
            const btn = form.querySelector('button[type="submit"]');
            
            if (method.toUpperCase() === 'DELETE' && !confirm('Hapus data ini?')) return;
            
            const originalText = btn.innerHTML;
            btn.innerHTML = '...';
            btn.disabled = true;

            fetch(action, {
                method: method,
                headers: {
                    'X-CSRF-TOKEN': document.querySelector('input[name="_token"]')?.value || '',
                    'Accept': 'application/json'
                }
            })
            .then(r => r.json())
            .then(res => {
                if (res.success) {
                    if (method.toUpperCase() === 'DELETE') {
                        const tr = form.closest('tr');
                        if (tr) {
                            tr.style.backgroundColor = '#fee2e2';
                            setTimeout(() => tr.remove(), 400);
                        }
                    } else if (method.toUpperCase() === 'PUT') {
                        const tr = form.closest('tr');
                        if (tr && res.data) {
                            const viewsTd = tr.querySelector('td[data-label="Views"]');
                            const likesTd = tr.querySelector('td[data-label="Like"]');
                            const commentsTd = tr.querySelector('td[data-label="Komen"]');
                            const totalTd = tr.querySelector('td[data-label="Total"] strong');
                            const sourceTd = tr.querySelector('td[data-label="Source"] span');
                            
                            if (totalTd) totalTd.innerText = res.data.views;
                            if (viewsTd) viewsTd.innerText = res.data.views;
                            if (likesTd) likesTd.innerText = res.data.likes;
                            if (commentsTd) commentsTd.innerText = res.data.comments;
                            if (sourceTd) {
                                sourceTd.innerText = res.data.source;
                                sourceTd.className = 'cp-badge ok';
                            }
                            btn.innerHTML = 'Ok!';
                            setTimeout(() => { btn.innerHTML = 'Sync'; btn.disabled = false; }, 2000);
                            return;
                        }
                    }
                } else {
                    alert(res.message || 'Terjadi kesalahan.');
                    btn.innerHTML = originalText;
                    btn.disabled = false;
                }
            })
            .catch(err => {
                alert('Terjadi kesalahan koneksi.');
                btn.innerHTML = originalText;
                btn.disabled = false;
            });
        }
    });
    const tabs = document.querySelectorAll('[data-tab]');
    const sections = document.querySelectorAll('[data-section]');
    function activateTab(name){
        tabs.forEach(btn => btn.classList.toggle('active', btn.dataset.tab === name));
        sections.forEach(sec => sec.classList.toggle('active', sec.dataset.section === name));
        if (history.replaceState) history.replaceState(null, '', '#' + name);
    }
    tabs.forEach(btn => btn.addEventListener('click', function(e){ if(this.tagName === 'BUTTON'){ e.preventDefault(); activateTab(this.dataset.tab); } }));
    const hash = (window.location.hash || '').replace('#','');
    if(['dashboard','form','report'].includes(hash)) activateTab(hash);

    const syncBtn = document.getElementById('readMetricsBtn');
    function cleanUrl(value){ value = (value || '').trim(); if(!value) return ''; if(value.includes('@user/video') || value.includes('@user/post') || value.includes('/user/status') || value.includes('/p/...')) return ''; return value; }
    function buildPlatformSourceText(platforms){ return Object.keys(platforms || {}).map(function(name){ const row = platforms[name] || {}; return name + ':' + (row.ok ? 'ok' : 'fail') + ':' + (row.source || 'manual'); }).join(' | '); }
    if(syncBtn){ syncBtn.addEventListener('click', async function(){
        const items = document.querySelectorAll('.cp-item-group');
        let hasLink = false;
        items.forEach(g => {
            const tk = cleanUrl(g.querySelector('.tiktokLinkInput')?.value);
            const ig = cleanUrl(g.querySelector('.instagramLinkInput')?.value);
            const th = cleanUrl(g.querySelector('.threadsLinkInput')?.value);
            const xl = cleanUrl(g.querySelector('.xLinkInput')?.value);
            if(tk || ig || th || xl) hasLink = true;
        });
        if(!hasLink){ alert('Isi minimal satu link sosial media di salah satu baris konten terlebih dahulu.'); return; }
        const oldText = syncBtn.innerText; syncBtn.disabled = true; syncBtn.innerText = 'Sinkronkan... Loading...';
        
        for (let i = 0; i < items.length; i++) {
            const g = items[i];
            const tk = cleanUrl(g.querySelector('.tiktokLinkInput')?.value);
            const ig = cleanUrl(g.querySelector('.instagramLinkInput')?.value);
            const th = cleanUrl(g.querySelector('.threadsLinkInput')?.value);
            const xl = cleanUrl(g.querySelector('.xLinkInput')?.value);
            const msg = g.querySelector('.metricMessage');
            if(!tk && !ig && !th && !xl) { if(msg){ msg.className='metricMessage cp-message'; msg.innerText='(Dilewati, tidak ada link)';} continue; }
            if(msg){ msg.className='metricMessage cp-message'; msg.innerText='Mengambil metrik...'; }
            
            const payload = { tiktok_link: tk, instagram_link: ig, ig_link: ig, threads_link: th, x_link: xl, twitter_link: xl };
            try { 
                const url = new URL('{{ route('marketing.content-posting.metrics') }}', window.location.origin); 
                Object.keys(payload).forEach(key => { if(payload[key]) url.searchParams.set(key, payload[key]); }); 
                const response = await fetch(url.toString(), { method:'GET', headers:{'Accept':'application/json','X-Requested-With':'XMLHttpRequest'} }); 
                const data = await response.json(); 
                if(data.title && g.querySelector('.judulInput')) g.querySelector('.judulInput').value = data.title; 
                if(data.views !== undefined && g.querySelector('.viewsInput')) g.querySelector('.viewsInput').value = data.views; 
                if(data.likes !== undefined && g.querySelector('.likesInput')) g.querySelector('.likesInput').value = data.likes; 
                if(data.comments !== undefined && g.querySelector('.commentsInput')) g.querySelector('.commentsInput').value = data.comments; 
                const platformSources = data.source_detail || buildPlatformSourceText(data.platforms || {}); 
                if(msg){
                    msg.innerText = (data.message || (data.ok ? 'Metrik disinkronkan.' : 'Gagal baca metrik.')) + (platformSources ? ' (' + platformSources + ')' : '');
                    msg.className = 'metricMessage cp-message ' + (data.ok ? 'ok' : 'err');
                }
            } catch(e){ 
                if(msg){ msg.className='metricMessage cp-message err'; msg.innerText='Gagal menghubungi backend.'; } 
                if(window.console) console.error(e); 
            }
        }
        syncBtn.disabled = false; syncBtn.innerText = oldText;
    }); }

    const addBtn = document.getElementById('addContentBtn');
    const container = document.getElementById('itemsContainer');
    if(addBtn && container){
        let itemCount = 1;
        addBtn.addEventListener('click', function(){
            const html = `
<div class="cp-item-group" data-index="${itemCount}" style="margin-top:20px; border-top:1px dashed var(--cp-border); padding-top:20px;">
<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:14px;"><h4 style="font-size:14px;color:var(--cp-main);margin:0;">Data Konten #${itemCount+1}</h4><button type="button" class="remove-btn cp-btn small outline" style="color:var(--danger);border-color:var(--danger)">Hapus</button></div>
<div class="cp-grid"><div><label class="cp-label">Link TikTok</label><input class="cp-field tiktokLinkInput" type="url" name="items[${itemCount}][tiktok_link]" placeholder="https://www.tiktok.com/@user/video/..."></div><div><label class="cp-label">Link Instagram</label><input class="cp-field instagramLinkInput" type="url" name="items[${itemCount}][ig_link]" placeholder="https://www.instagram.com/p/.../"></div><div><label class="cp-label">Link Threads</label><input class="cp-field threadsLinkInput" type="url" name="items[${itemCount}][threads_link]" placeholder="https://www.threads.net/@user/post/..."></div><div><label class="cp-label">Link X / Twitter</label><input class="cp-field xLinkInput" type="url" name="items[${itemCount}][x_link]" placeholder="https://x.com/user/status/..."></div><div><label class="cp-label">Judul / Caption</label><input class="cp-field judulInput" type="text" name="items[${itemCount}][judul]" placeholder="Otomatis dari API atau isi manual"></div></div><div class="cp-grid three" style="margin-top:14px"><div><label class="cp-label">Views</label><input class="cp-field viewsInput" type="number" min="0" name="items[${itemCount}][manual_views]" value="0"></div><div><label class="cp-label">Like</label><input class="cp-field likesInput" type="number" min="0" name="items[${itemCount}][manual_likes]" value="0"></div><div><label class="cp-label">Komen</label><input class="cp-field commentsInput" type="number" min="0" name="items[${itemCount}][manual_comments]" value="0"></div></div><div style="margin-top:14px"><label class="cp-label">Aktivitas</label><div class="cp-checks"><label class="cp-check"><input type="checkbox" name="items[${itemCount}][activity_upload]" value="1" checked> Upload</label><label class="cp-check"><input type="checkbox" name="items[${itemCount}][activity_reply_comment]" value="1"> Balas Komen</label></div><input type="hidden" name="items[${itemCount}][tiktok_api_type]" value="read_views"></div><div style="margin-top:14px"><label class="cp-label">Keterangan / Bukti Komplain</label><textarea class="cp-textarea" name="items[${itemCount}][keterangan]" placeholder="Catatan opsional, bukti screenshot, atau komplain yang masuk"></textarea></div><div class="metricMessage cp-message"></div>
</div>`;
            container.insertAdjacentHTML('beforeend', html);
            itemCount++;
        });
        container.addEventListener('click', function(e){
            if(e.target && e.target.classList.contains('remove-btn')){
                e.target.closest('.cp-item-group').remove();
            }
        });
    }
    function initSearchTable(tableId, searchId){ const table=document.getElementById(tableId); if(!table) return; const rows=[...table.querySelectorAll('tbody tr')]; const search=document.getElementById(searchId); if(search) search.addEventListener('input', e=>{const q=e.target.value.toLowerCase(); rows.forEach(r=>{if(r.innerText.toLowerCase().includes(q)) r.style.display=''; else r.style.display='none';});}); }
    initSearchTable('detailReportTable','detailSearch');
    function paginateDaily(){ const wrap=document.getElementById('dailyCards'); if(!wrap || wrap.dataset.paginate !== '1') return; const cards=[...wrap.querySelectorAll('[data-daily-card]')]; const perPage=parseInt(wrap.dataset.perPage||'5',10); const info=document.getElementById('dailyPaginationInfo'); const buttons=document.getElementById('dailyPaginationButtons'); let page=1; function render(){ const total=Math.max(1, Math.ceil(cards.length/perPage)); cards.forEach((card,idx)=>{card.hidden = idx < (page-1)*perPage || idx >= page*perPage;}); if(info) info.innerText='Menampilkan '+cards.length+' hari · halaman '+page+' / '+total; if(buttons){ buttons.innerHTML=''; const prev=document.createElement('button'); prev.className='cp-page-btn'; prev.innerText='Prev'; prev.disabled=page<=1; prev.onclick=()=>{page--;render();}; buttons.appendChild(prev); for(let i=1;i<=total;i++){ const b=document.createElement('button'); b.className='cp-page-btn'+(i===page?' active':''); b.innerText=i; b.onclick=()=>{page=i;render();}; buttons.appendChild(b);} const next=document.createElement('button'); next.className='cp-page-btn'; next.innerText='Next'; next.disabled=page>=total; next.onclick=()=>{page++;render();}; buttons.appendChild(next);} } render(); }
    paginateDaily();
    
    const checklistForm = document.getElementById('checklistForm');
    const submitBtn = document.getElementById('submitChecklistBtn');
    if (checklistForm && submitBtn) {
        checklistForm.addEventListener('submit', function() {
            submitBtn.disabled = true;
            submitBtn.innerText = 'Menyimpan...';
        });
    }
});
</script>

@include('Temp.Investor.footer')
